      case 'analytical':
      default:
        return contents.join(' ');
    }
  }

  private aggregateTags(expressions: Expression[]): string[] {
    const allTags = expressions.flatMap(e => e.metadata.tags || []);
    return [...new Set(allTags)];
  }
